from langchain_experimental.graph_transformers import LLMGraphTransformer

# Constrain entity and relation types to a fixed schema
transformer = LLMGraphTransformer(
    llm=ChatOpenAI(model="gpt-4o-mini", temperature=0),
    allowed_nodes=["Model", "Architecture", "Mechanism", "Paper", "Author"],
    allowed_relationships=["USES", "EXTENDS", "INTRODUCED_IN", "AUTHORED_BY"],
    strict_mode=True,   # reject entities/relations not in the allowed lists
)

# Post-process: merge near-duplicate entities
from difflib import SequenceMatcher

def merge_duplicates(graph, similarity_threshold: float = 0.85):
    """Find and merge entity nodes with highly similar names."""
    entities = graph.query("MATCH (n) RETURN n.id AS id, labels(n)[0] AS label")
    by_label: dict[str, list[str]] = {}
    for e in entities:
        by_label.setdefault(e["label"], []).append(e["id"])

    merges = []
    for label, ids in by_label.items():
        for i in range(len(ids)):
            for j in range(i + 1, len(ids)):
                ratio = SequenceMatcher(None, ids[i].lower(), ids[j].lower()).ratio()
                if ratio >= similarity_threshold:
                    merges.append((ids[i], ids[j]))

    for canonical, duplicate in merges:
        graph.query(
            f"MATCH (a {{id: '{duplicate}'}}), (b {{id: '{canonical}'}}) "
            f"CALL apoc.refactor.mergeNodes([a, b]) YIELD node RETURN node"
        )
    return len(merges)

from langchain_core.runnables import RunnablePassthrough, RunnableLambda
from langchain_core.prompts import ChatPromptTemplate
from langchain_core.output_parsers import StrOutputParser
from langchain_openai import ChatOpenAI

llm = ChatOpenAI(model="gpt-4o-mini", temperature=0)

# Classifier: is this a relational query requiring graph traversal?
classify_prompt = ChatPromptTemplate.from_template(
    """Does this question ask about relationships between entities, 
multi-hop facts, or how things are connected to each other?
Reply with only "graph" or "vector".

Question: {question}"""
)
classifier = classify_prompt | llm | StrOutputParser()

answer_prompt = ChatPromptTemplate.from_template(
    """Answer using the context below.

Context:
{context}

Question: {question}"""
)

def route_query(inputs: dict) -> str:
    query_type = classifier.invoke({"question": inputs["question"]})
    if "graph" in query_type.lower():
        result = cypher_chain.invoke({"query": inputs["question"]})
        return result.get("result", "")
    else:
        docs = vector_retriever.invoke(inputs["question"])
        return "\n\n".join(d.page_content for d in docs)

hybrid_rag = (
    {
        "context": RunnableLambda(route_query),
        "question": RunnablePassthrough() | (lambda x: x["question"]),
    }
    | answer_prompt
    | llm
    | StrOutputParser()
)

def path_accuracy(
    query: str,
    expected_path: list[str],   # e.g. ["Transformer", "Attention", "BERT"]
    retriever_fn,
) -> float:
    """Fraction of expected path entities found in retrieved context."""
    results = retriever_fn(query)
    all_text = " ".join(r.page_content for r in results).lower()
    hits = sum(1 for entity in expected_path if entity.lower() in all_text)
    return hits / len(expected_path)

# Evaluation suite
test_cases = [
    {
        "query": "Which models use the attention mechanism from the Transformer paper?",
        "path": ["Transformer", "Attention", "BERT", "GPT"],
    },
    {
        "query": "What architecture does BERT extend?",
        "path": ["BERT", "Transformer"],
    },
]

for case in test_cases:
    flat_acc  = path_accuracy(case["query"], case["path"],
                              lambda q: vector_retriever.invoke(q))
    graph_acc = path_accuracy(case["query"], case["path"],
                              lambda q: [type("Doc", (), {"page_content": str(
                                  cypher_chain.invoke({"query": q}))})() ])
    print(f"Q: {case['query'][:50]}")
    print(f"  flat={flat_acc:.2f}  graph={graph_acc:.2f}")
